// TeacherReview is the public domain representation of a teacher_review row.
type TeacherReview struct {
	ID           uuid.UUID
	TenantID     uuid.UUID
	SubmissionID uuid.UUID
	QuestionNo   string
	OldMarks     float64
	NewMarks     float64
	Feedback     string
	Comment      string
	Actor        string
	CreatedAt    time.Time
}

// InsertTeacherReviewParams carries the values for a new teacher_review row.
type InsertTeacherReviewParams struct {
	TenantID     uuid.UUID
	SubmissionID uuid.UUID
	QuestionNo   string
	OldMarks     float64
	NewMarks     float64
	Feedback     string
	Comment      string
	Actor        string
}

// InsertTeacherReview appends a per-question review row. It is append-only;
// callers may insert multiple rows for the same question_no to represent
// successive overrides.
func (s *Store) InsertTeacherReview(ctx context.Context, p InsertTeacherReviewParams) (TeacherReview, error) {
	row, err := s.queries.InsertTeacherReview(ctx, db.InsertTeacherReviewParams{
		TenantID:     p.TenantID,
		SubmissionID: p.SubmissionID,
		QuestionNo:   p.QuestionNo,
		OldMarks:     p.OldMarks,
		NewMarks:     p.NewMarks,
		Feedback:     p.Feedback,
		Comment:      p.Comment,
		Actor:        p.Actor,
	})
	if err != nil {
		return TeacherReview{}, fmt.Errorf("store: InsertTeacherReview: %w", err)
	}
	return teacherReviewFromDB(row), nil
}

// ListTeacherReviews returns all teacher_review rows for a submission within a
// tenant, ordered by created_at ASC (oldest first). The latest row per
// question_no represents the current override when merging.
func (s *Store) ListTeacherReviews(ctx context.Context, tenantID uuid.UUID, submissionID uuid.UUID) ([]TeacherReview, error) {
	rows, err := s.queries.ListTeacherReviews(ctx, db.ListTeacherReviewsParams{
		TenantID:     tenantID,
		SubmissionID: submissionID,
	})
	if err != nil {
		return nil, fmt.Errorf("store: ListTeacherReviews: %w", err)
	}
	result := make([]TeacherReview, 0, len(rows))
	for _, row := range rows {
		result = append(result, teacherReviewRowFromDB(row))
	}
	return result, nil
}

// ─────────────────────────────────────────────────────────────────────────────
// FinalGrade domain type and repository methods
// ─────────────────────────────────────────────────────────────────────────────

// FinalGrade is the public domain representation of a final_grade row.
// InsertFinalGrade uses UPSERT semantics: first approve inserts, re-approve after
// a regrade updates the row in place (updated_at bumps). Prior grades are preserved
// in the audit_event trail. There is no delete method.
type FinalGrade struct {
	ID           uuid.UUID
	TenantID     uuid.UUID
	SubmissionID uuid.UUID
	Total        float64
	MaxTotal     float64
	Score100     float64
	GradedKey    string
	ApprovedBy   string
	ApprovedAt   time.Time
	CreatedAt    time.Time
}

// InsertFinalGradeParams carries the values for a new final_grade row.
type InsertFinalGradeParams struct {
	TenantID     uuid.UUID
	SubmissionID uuid.UUID
	Total        float64
	MaxTotal     float64
	Score100     float64
	GradedKey    string
	ApprovedBy   string
	ApprovedAt   time.Time
}

// InsertFinalGrade upserts an approval snapshot into final_grade and returns the
// persisted row. On first approve it inserts; on re-approve after a regrade it
// updates total/max_total/score_100/graded_key/approved_by/approved_at in place
// (updated_at bumps). Prior grades are preserved in the audit_event trail.
func (s *Store) InsertFinalGrade(ctx context.Context, p InsertFinalGradeParams) (FinalGrade, error) {
	row, err := s.queries.InsertFinalGrade(ctx, db.InsertFinalGradeParams{
		TenantID:     p.TenantID,
		SubmissionID: p.SubmissionID,
		Total:        p.Total,
		MaxTotal:     p.MaxTotal,
		Score100:     p.Score100,
		GradedKey:    p.GradedKey,
		ApprovedBy:   p.ApprovedBy,
		ApprovedAt:   pgtype.Timestamptz{Time: p.ApprovedAt, Valid: true},
	})
	if err != nil {
		return FinalGrade{}, fmt.Errorf("store: InsertFinalGrade: %w", err)
	}
	return finalGradeFromInsertRow(row), nil
}

// GetFinalGrade retrieves the final_grade row for the submission (at most one
// exists per tenant+submission); returns ErrNotFound if the submission has not
// been approved.
func (s *Store) GetFinalGrade(ctx context.Context, tenantID uuid.UUID, submissionID uuid.UUID) (FinalGrade, error) {
	row, err := s.queries.GetFinalGrade(ctx, db.GetFinalGradeParams{
		TenantID:     tenantID,
		SubmissionID: submissionID,
	})
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return FinalGrade{}, fmt.Errorf("GetFinalGrade %s: %w", submissionID, ErrNotFound)
		}
		return FinalGrade{}, fmt.Errorf("store: GetFinalGrade: %w", err)
	}
	return finalGradeFromGetRow(row), nil
}

// ─────────────────────────────────────────────────────────────────────────────
// Mapping helpers — db package types → public domain types
// ─────────────────────────────────────────────────────────────────────────────

// submissionFromDB converts a sqlc-generated db.Submission into the public
// Submission type, mapping pgtype nullable wrappers to Go pointer semantics.
func submissionFromDB(r db.Submission) Submission {
	return Submission{
		ID:                  r.ID,
		TenantID:            r.TenantID,
		AssessmentVersionID: nullUUIDToPtr(r.AssessmentVersionID),
		StudentID:           nullUUIDToPtr(r.StudentID),
		State:               contracts.SubmissionState(r.State),
		CurrentStage:        pgtypeTextToPtr(r.CurrentStage),
		Attempt:             int(r.Attempt),
		ErrorDetail:         pgtypeTextToPtr(r.ErrorDetail),
		SourcePDFKey:        pgtypeTextToPtr(r.SourcePdfKey),
		TranscriptKey:       pgtypeTextToPtr(r.TranscriptKey),
		GradedKey:           pgtypeTextToPtr(r.GradedKey),
		CreatedAt:           r.CreatedAt.Time,
		UpdatedAt:           r.UpdatedAt.Time,
	}
}

// auditEventFromDB converts a sqlc-generated db.AuditEvent into the public
// AuditEvent type.
func auditEventFromDB(r db.AuditEvent) AuditEvent {
	return AuditEvent{
		ID:         r.ID,
		TenantID:   r.TenantID,
		EntityType: r.EntityType,
		EntityID:   nullUUIDToPtr(r.EntityID),
		Actor:      r.Actor,
		Action:     r.Action,
		OldValue:   r.OldValue,
		NewValue:   r.NewValue,
		Reason:     r.Reason,
		CreatedAt:  r.CreatedAt.Time,
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// Type conversion utilities
// ─────────────────────────────────────────────────────────────────────────────

func ptrUUIDToNullUUID(p *uuid.UUID) uuid.NullUUID {
	if p == nil {
		return uuid.NullUUID{}
	}
	return uuid.NullUUID{UUID: *p, Valid: true}
}

func nullUUIDToPtr(n uuid.NullUUID) *uuid.UUID {
	if !n.Valid {
		return nil
	}
	v := n.UUID
	return &v
}

func ptrStringToPgtypeText(p *string) pgtype.Text {
	if p == nil {
		return pgtype.Text{}
	}
	return pgtype.Text{String: *p, Valid: true}
}

func pgtypeTextToPtr(t pgtype.Text) *string {
	if !t.Valid {
		return nil
	}
	v := t.String
	return &v
}

// nullJSON returns nil when b is empty so pgx sends a SQL NULL instead of an
// empty byte slice (which would fail the jsonb cast).
func nullJSON(b []byte) []byte {
	if len(b) == 0 {
		return nil
	}
	return b
}

